# ---- parse: P&L real por data ----
real = {}
for line in RAW.strip().splitlines():
    line = line.strip()
    if not line:
        continue
    if line.startswith('"') and line.endswith('"'):
        line = line[1:-1]
    line = line.replace('""', '"').rstrip().rstrip('"').rstrip()
    fields = next(csv.reader([line]))
    date = fields[0][:10]
    pnl = float(fields[7])
    real[date] = real.get(date, 0.0) + pnl

# ---- compara ----
rows = []
for d in sorted(ANALYTIC):
    a = ANALYTIC[d]
    r = real.get(d, None)
    if r is None:
        continue
    rows.append((d, a, r, a - r))   # diff = quanto o QC "comeu" vs analitico

tot_a = sum(a for _, a, _, _ in rows)
tot_r = sum(r for _, _, r, _ in rows)

print(f"Trades reconciliados: {len(rows)}")
print(f"NET ANALITICO total : ${tot_a:,.0f}")
print(f"P&L REAL do QC total: ${tot_r:,.0f}   (QC End Equity 98624 -> -1376 confere)")
print(f"DIVERGENCIA total   : ${tot_a - tot_r:,.0f}")
print("="*72)
print("PIORES DIVERGENCIAS (analitico - real), os trades onde a saida quebrou:")
print(f"{'data':<12}{'analitico':>12}{'real QC':>12}{'diff':>12}")
for d, a, r, diff in sorted(rows, key=lambda x: -abs(x[3]))[:12]:
    print(f"{d:<12}{a:>12,.0f}{r:>12,.0f}{diff:>12,.0f}")
